enum LogLevel {
  debug,
  info,
  warning,
  error,
}

class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic> data;

  LogEntry({
    required this.timestamp,
    required this.level,
    required this.category,
    required this.message,
    required this.data,
  });

  @override
  String toString() {
    return '[${timestamp.toIso8601String()}] [${level.name.toUpperCase()}] [$category] $message';
  }

  Map<String, dynamic> toJson() {
    return {
      'timestamp': timestamp.toIso8601String(),
      'level': level.name,
      'category': category,
      'message': message,
      'data': data,
    };
  }
}

class SecureHttpClient extends http.BaseClient {
  final http.Client _inner;
  final SecureProductionLogger _logger;

  SecureHttpClient(this._inner, this._logger);

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) async {
    final httpRequest = http.Request(request.method, request.url)
      ..headers.addAll(request.headers);
    
    if (request is http.Request) {
      httpRequest.bodyBytes = request.bodyBytes;
    }

    _logger.logHttpRequest(httpRequest);

    try {
      final response = await _inner.send(request);
      final responseBytes = await response.stream.toBytes();
      final httpResponse = http.Response.bytes(
        responseBytes,
        response.statusCode,
        headers: response.headers,
        request: request,
      );

      _logger.logHttpResponse(httpResponse);

      return http.StreamedResponse(
        http.ByteStream.fromBytes(responseBytes),
        response.statusCode,
        headers: response.headers,
        request: request,
      );
    } catch (e) {
      debugPrint('[HTTP_ERROR] ${e.toString()}');
      rethrow;
    }
  }
}

